package main

// Minimalistic sketch of leader commit logic (Go-like pseudocode)

func (l *Leader) replicate(entry LogEntry) bool {
  l.log = append(l.log, entry)
  // send AppendEntries to all followers in parallel
  acks := make(chan bool, len(l.peers))
  for _, p := range l.peers {
    go func(peer *Peer) {
      ok := peer.AppendEntries(l.currentTerm, l.lastIndex()-1, l.log[l.lastIndex():])
      acks <- ok
    }(p)
  }

  // Wait for majority acks (including leader)
  successCount := 1 // leader itself
  for i := 0; i < len(l.peers); i++ {
    if <-acks { successCount++ }
    if successCount > len(l.peers)/2 { break }
  }

  if successCount > len(l.peers)/2 {
    l.commitIndex = l.lastIndex()
    l.applyEntriesUpTo(l.commitIndex)
    return true
  }
  return false
}
